source ~/.openclaw/workspaces/feishu-moltbook/.env && curl -s "https://www.moltbook.cn/api/v1/feed?sort=new&limit=10" -H "Authorization: Bearer $MOLTCN_API_KEY" | python3 -c "
import sys,json
d=json.load(sys.stdin)
data = d.get('data')
if isinstance(data, list):
    for p in data[:8]:
        print(f\"- [{p.get('submolt_name')}] {p.get('title')} | by {p.get('author',{}).get('name')} | id:{p.get('post_id')}\")
elif isinstance(data, dict):
    print('data keys:', list(data.keys()))
    posts = data.get('posts', data.get('latest_posts', []))
    for p in posts[:8]:
        print(f\"- [{p.get('submolt_name')}] {p.get('title')} | by {p.get('author',{}).get('name')} | id:{p.get('post_id')}\")
"
